import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ---------------------------------------------------------------
  // QUOTE — base premiums and edge cases
  // ---------------------------------------------------------------

  it.todo("empty item list returns premium 5 G (only processing fee)");

  it.todo("single plain sword for newcomer first insurance: 100 + 10 + 5 = 115 G");

  it.todo("single plain amulet for newcomer first insurance: 60 + 6 + 5 = 71 G");

  it.todo("single plain staff for newcomer first insurance: 80 + 8 + 5 = 93 G");

  it.todo("single plain potion for newcomer first insurance: 40 + 4 + 5 = 49 G");

  // ---------------------------------------------------------------
  // QUOTE — components (runes, moonstones) and block discount
  // ---------------------------------------------------------------

  it.todo("2 runes have base premium 50 G (no block, requires exactly 3)");

  it.todo("3 runes have base premium 60 G (block applies)");

  it.todo("4 runes have base premium 100 G (no block — block requires exactly 3)");

  it.todo("7 runes have base premium 175 G (one block of 3 at 60 + 4 singles at 25 = 60+100)");

  // ---------------------------------------------------------------
  // QUOTE — "alike" components clarification (❓)
  // ---------------------------------------------------------------

  it.todo("2 runes + 1 moonstone: 75 G base premium (no block — different types)");

  it.todo("3 runes + 3 moonstones: 120 G base premium (two separate blocks)");

  // ---------------------------------------------------------------
  // QUOTE — item-specific modifiers (cursed, high enchantment)
  // ---------------------------------------------------------------

  it.todo("cursed sword adds 50% surcharge to that item's base premium (curse rule in isolation)");

  it.todo("sword with enchantment 5 triggers high-enchantment surcharge (threshold inclusive)");

  it.todo("sword with enchantment 4 has no high-enchantment surcharge");

  it.todo("cursed sword with enchantment 5 stacks both surcharges on the item's base premium");

  // ---------------------------------------------------------------
  // QUOTE — modifier scope on multi-item policies (❓)
  // ---------------------------------------------------------------

  it.todo("policy with cursed sword + plain amulet: curse surcharge applies only to sword's base (210 G before further modifiers/fee)");

  it.todo("item-specific modifiers apply to item base premium; policy-wide modifiers apply to policy base premium; fee added at the end");

  // ---------------------------------------------------------------
  // QUOTE — policy-wide modifiers
  // ---------------------------------------------------------------

  it.todo("long-standing customer (2 years exactly): 20% loyalty discount applies");

  it.todo("customer with 1 year: no loyalty discount");

  it.todo("first insurance: 10% surcharge per item");

  it.todo("follow-up contract (after first quote in scenario): 15% policy-wide discount applies");

  it.todo("each item in a follow-up quote still incurs the per-item first insurance surcharge");

  // ---------------------------------------------------------------
  // QUOTE — rounding (rounded UP in MHPCO favor)
  // ---------------------------------------------------------------

  it.todo("premium computed at 197.5 G rounds UP to 198 G");

  it.todo("intermediate amounts are kept as fractions; only final premium is rounded");

  // ---------------------------------------------------------------
  // QUOTE — integration examples
  // ---------------------------------------------------------------

  it.todo("newcomer cursed sword (steel, enchantment 3): 100 + 50 + 10 + 5 = 165 G");

  it.todo("3-year customer's 2nd contract, cursed sword (steel, enchantment 7): 100 + 50 + 30 − 20 + 10 − 15 + 5 = 160 G");

  // ---------------------------------------------------------------
  // QUOTE — errors
  // ---------------------------------------------------------------

  it.todo("quote with unknown item type (e.g. broomstick) throws/errors");

  // ---------------------------------------------------------------
  // CLAIM — base reimbursement and deductible
  // ---------------------------------------------------------------

  it.todo("regular sword (steel, enchantment 3) damage 500 G → payout 400 G (full − 100 deductible)");

  it.todo("rune (no enchantment, no material) damage 200 G → payout 100 G (full − 100 deductible)");

  it.todo("deductible applies once per damaged item: dragon attack damaging sword 500 G + amulet 300 G → payout 600 G");

  // ---------------------------------------------------------------
  // CLAIM — high enchantment clause (≥8 → 50%)
  // ---------------------------------------------------------------

  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then 100 deductible)");

  it.todo("sword with enchantment 7 (below 8): standard reimbursement applies (no 50% clause)");

  // ---------------------------------------------------------------
  // CLAIM — dragon material clause (full reimbursement)
  // ---------------------------------------------------------------

  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full − 100 deductible)");

  // ---------------------------------------------------------------
  // CLAIM — interaction between enchantment threshold and dragon material
  // ---------------------------------------------------------------

  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins, then deductible)");

  it.todo("dragon-material sword, enchantment 8 exactly, damage 1000 G → payout 400 G (high-enchantment clause applies, then deductible)");

  // ---------------------------------------------------------------
  // CLAIM — multiple items of the same type (❓)
  // ---------------------------------------------------------------

  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G");

  it.todo("two sword damage entries → each treated as a separate damage with its own deductible");

  it.todo("more damage entries of a type than insured items of that type → error (claim rejected)");

  // ---------------------------------------------------------------
  // CLAIM — cap exhaustion
  // ---------------------------------------------------------------

  it.todo("policy with sword + amulet: insurance sum 1600 G, cap 3200 G");

  it.todo("cursed sword: cap is 2000 G based on unmodified insurance value (premium modifiers do not raise cap)");

  it.todo("policy with sword + 3 runes (block): insurance sum 1750 G (block affects premium only, not insurance sum)");

  it.todo("sword (cap 2000 G): first claim 1500 G → payout 1400 G, remaining cap 600 G");

  it.todo("sword (cap 2000 G): second successive claim 1500 G → payout 600 G (capped), remaining cap 0 G");

  // ---------------------------------------------------------------
  // CLAIM — rounding (rounded DOWN in MHPCO favor)
  // ---------------------------------------------------------------

  it.todo("payout computed at 350.5 G rounds DOWN to 350 G");

  it.todo("intermediate payout amounts kept as fractions; only final payout rounded");

  // ---------------------------------------------------------------
  // CLAIM — errors
  // ---------------------------------------------------------------

  it.todo("claim references damage entry whose item is not part of the policy → error");

  it.todo("claim references damage entry with unknown item type → error");

  it.todo("claim contains damage entry with negative amount (e.g. -200) → error");

  // ---------------------------------------------------------------
  // CLI / scenario-level integration
  // ---------------------------------------------------------------

  it.todo("scenario with one quote step writes results array with premium integer");

  it.todo("scenario with quote then claim: claim references policy by zero-based step index");

  it.todo("results array length and order matches input steps array");

  it.todo("CLI exits non-zero on unknown item type in quote (no results written to stdout)");

  it.todo("CLI exits non-zero on claim referencing item not in policy");

  it.todo("CLI exits non-zero on claim with negative damage amount");

  it.todo("CLI exits non-zero on too-many-damages-for-type");
});

